const AREA_VIEWS=['MCQs','Simulations','Flashcards','Readings'];
const GLOBAL_VIEWS=['Dashboard','Missed Log','Calendar','Exam Mode','System Health','Backup & Restore'];
const NAV=['Dashboard','MCQs','Simulations','Flashcards','Readings','Missed Log','Calendar','Exam Mode','System Health','Backup & Restore','Dark Mode'];
const $=id=>document.getElementById(id);
function freshState(){return {version:APP_VERSION,section:'ethics',view:'Dashboard',answered:{},missed:{},progress:{},flash:{},flashIndex:{},showBack:false,sim:{},quiz:null,examRun:null,dark:localStorage.dark==='1',examDate:'2026-08-31'};}
let state={...freshState(),...JSON.parse(localStorage.getItem(STORAGE_KEY)||'{}')};
function save(){state.version=APP_VERSION;localStorage.setItem(STORAGE_KEY,JSON.stringify(state));}
function secObj(id){return SECTIONS.find(s=>s.id===id)||SECTIONS[0]}
function sectionName(id){if(id==='mixed')return 'Mixed'; let s=secObj(id); return s.name;}
function areaQs(sec=state.section){return QUESTIONS.filter(q=>q.sec===sec)}
function areaSims(sec=state.section){return SIMS.filter(s=>s.sec===sec)}
function areaFlash(sec=state.section){return FLASHCARDS.filter(f=>f.sec===sec)}
function today(){return new Date().toISOString().slice(0,10)}
function logActivity(type,sec,detail){let d=today();state.progress[d]=state.progress[d]||[];state.progress[d].push({time:new Date().toLocaleTimeString(),type,sec,detail});}
function render(){document.body.classList.toggle('dark',!!state.dark);renderSections();renderNav();let v=state.view;if(v==='Dashboard')dashboard();else if(v==='MCQs')mcqs();else if(v==='Simulations')sims();else if(v==='Flashcards')flash();else if(v==='Readings')read();else if(v==='Missed Log')missed();else if(v==='Calendar')calendar();else if(v==='Exam Mode')exam();else if(v==='System Health')systemHealth();else if(v==='Backup & Restore')backup();}
function renderSections(){let active=AREA_VIEWS.includes(state.view);$('sections').innerHTML=SECTIONS.map(s=>`<button ${active?'':'disabled'} class="${state.section===s.id&&active?'active':''}" onclick="state.section='${s.id}';save();render()"><span class="area-title">Area ${s.roman}</span><span class="area-name">${s.name}</span></button>`).join('');}
function renderNav(){$('nav').innerHTML=NAV.map(v=>`<button class="${state.view===v?'active':''}" onclick="${v==='Dark Mode'?'toggleDark()':`state.view='${v}';save();render()`}">${v}</button>`).join('');}
function pct(n,d){return d?Math.round(n/d*100):0}
function dashboard(){let answered=Object.values(state.answered);let correct=answered.filter(a=>a.correct).length;let d=Math.ceil((new Date(state.examDate)-new Date())/86400000);$('app').innerHTML=`<div class="card hero"><h2>CPA AUD Command Center</h2><div class="grid"><div><b>Running Score</b><div class="metric">${pct(correct,answered.length)}%</div><p class="muted">Based on attempted MCQs.</p></div><div><b>Days to Exam</b><div class="metric">${d}</div><p><span class="pill">${state.examDate}</span></p></div><div><b>Missed Questions</b><div class="metric">${Object.keys(state.missed).length}</div><p class="muted">Automatically captured for review.</p></div><div><b>Today's Activity</b><div class="metric">${(state.progress[today()]||[]).length}</div><p class="muted">Logged actions today.</p></div></div></div><div class="card"><h2>Blueprint Areas</h2><div class="grid">${SECTIONS.map(s=>{let qs=QUESTIONS.filter(q=>q.sec===s.id), done=qs.filter(q=>state.answered[q.id]).length, cor=qs.filter(q=>state.answered[q.id]?.correct).length;return `<div class="card"><span class="pill">Area ${s.roman}</span><h3>${s.name}</h3><div class="metric">${pct(cor,done)}%</div><div class="bar"><span style="width:${pct(done,qs.length)}%"></span></div><p class="muted">${qs.length} MCQs · ${areaSims(s.id).length} simulations · ${areaFlash(s.id).length} flashcards · Weight: ${s.weight}</p><div class="actions"><button onclick="state.section='${s.id}';state.view='MCQs';save();render()">MCQs</button><button onclick="state.section='${s.id}';state.view='Simulations';save();render()">Simulations</button></div></div>`}).join('')}</div></div>`}
function mcqs(){let qs=areaQs();$('app').innerHTML=`<div class="card"><h2>${sectionName(state.section)} — MCQs</h2><p class="muted">Questions are numbered 1…N and stop exactly at the selected sample size.</p><div class="actions">${[5,10,20].map(n=>`<button ${qs.length<n?'disabled title="Only '+qs.length+' questions available"':''} class="${n<=10?'primary':''}" onclick="startQuiz(${n})">Start ${n}</button>`).join('')}<button onclick="startQuiz(${qs.length})">All Area Questions</button></div><p><b>${qs.length}</b> available questions in this area. Each item includes source, difficulty, type, topic, and area metadata.</p></div>`}
function startQuiz(n,ids=null){let pool=(ids?ids.map(id=>QUESTIONS.find(q=>q.id===id)).filter(Boolean):areaQs()).sort(()=>Math.random()-.5);let selected=pool.slice(0,Math.min(n,pool.length));if(!selected.length){alert('No questions available.');return;}state.quiz={ids:selected.map(q=>q.id),idx:0,answered:false,selected:null,score:0};logActivity('Quiz Started',selected[0].sec,`${selected.length} questions`);save();quizQuestion();}
function qMeta(q){let src=q.sourceType==='CPA Released' ? `CPA Released Question · ${q.releaseYear||'Year needed'}` : q.sourceType;return `${src} · ${q.difficulty} · ${q.questionType} · ${q.topic}`;}
function quizQuestion(){let ids=state.quiz.ids, idx=state.quiz.idx, q=QUESTIONS.find(x=>x.id===ids[idx]);if(!q)return quizDone();$('app').innerHTML=`<div class="card"><h2>${sectionName(q.sec)} — MCQ</h2><p class="muted">Question ${idx+1} of ${ids.length} · ${qMeta(q)}</p><h3>${q.q}</h3>${q.choices.map((c,i)=>{let L=String.fromCharCode(65+i);let cls=state.quiz.answered?(L===q.ans?'correct':(state.quiz.selected===L?'wrong':'')):'';return `<button class="choice ${cls}" onclick="answer('${L}')"><b>${L}.</b> ${c}</button>`}).join('')}<div>${state.quiz.answered?`<p><b>${state.quiz.selected===q.ans?'Correct':'Incorrect'}.</b> ${q.exp}</p><button class="primary" onclick="nextQ()">${idx+1===ids.length?'Finish':'Next Question'}</button>`:''}</div></div>`}
function answer(letter){if(state.quiz.answered)return;let q=QUESTIONS.find(x=>x.id===state.quiz.ids[state.quiz.idx]);let correct=letter===q.ans;state.quiz.answered=true;state.quiz.selected=letter;if(correct)state.quiz.score++;state.answered[q.id]={correct,selected:letter,date:new Date().toISOString(),sec:q.sec,topic:q.topic};if(!correct){state.missed[q.id]=state.missed[q.id]||{id:q.id,sec:q.sec,topic:q.topic,q:q.q,ans:q.ans,exp:q.exp,count:0};state.missed[q.id].count++;state.missed[q.id].lastAnswer=letter;state.missed[q.id].lastMissed=new Date().toISOString()}logActivity(correct?'MCQ Correct':'MCQ Missed',q.sec,`${state.quiz.idx+1} of ${state.quiz.ids.length}`);save();quizQuestion();}
function nextQ(){state.quiz.idx++;state.quiz.answered=false;state.quiz.selected=null;save();state.quiz.idx>=state.quiz.ids.length?quizDone():quizQuestion();}
function quizDone(){let total=state.quiz.ids.length, score=state.quiz.score, p=pct(score,total);state.quiz=null;save();$('app').innerHTML=`<div class="card"><h2>Sample Completed</h2><p class="metric">${p}%</p><p>${score} correct of ${total}. The sample stopped at Question ${total} of ${total}.</p><button class="primary" onclick="state.view='MCQs';save();render()">Back to MCQs</button></div>`}
function sims(){let list=areaSims();$('app').innerHTML=`<div class="card"><h2>${sectionName(state.section)} — Simulations</h2><p class="muted">Use Open Exhibits, complete the response, save, and self-check.</p></div>`+list.map(s=>`<div class="card"><h3>${s.title}</h3><p>${s.prompt}</p><button onclick="toggleExhibits('${s.id}')">Open Exhibits</button><div id="ex-${s.id}" style="display:none">${s.exhibitBodies.map((b,i)=>`<pre><b>${s.exhibits[i]}</b>\n${b}</pre>`).join('')}</div><h4>Tasks</h4><ol>${s.tasks.map(t=>`<li>${t}</li>`).join('')}</ol><textarea id="sim-${s.id}">${(state.sim[s.id]||{}).text||''}</textarea><h4>Self-check rubric</h4>${s.rubric.map((r,i)=>`<label><input type="checkbox" id="${s.id}-${i}" ${(state.sim[s.id]||{}).checks?.[i]?'checked':''}> ${r}</label><br>`).join('')}<br><button class="primary" onclick="saveSim('${s.id}')">Save Response</button><button onclick="showRubric('${s.id}')">Show Rubric</button><div id="rub-${s.id}" class="muted"></div></div>`).join('')}
function toggleExhibits(id){let e=$('ex-'+id);e.style.display=e.style.display==='none'?'block':'none'}
function showRubric(id){let s=SIMS.find(x=>x.id===id);$('rub-'+id).innerHTML='<ol>'+s.rubric.map(r=>`<li>${r}</li>`).join('')+'</ol>'}
function saveSim(id){let sim=SIMS.find(s=>s.id===id);let checks=sim.rubric.map((_,i)=>$(`${id}-${i}`).checked);state.sim[id]={text:$(`sim-${id}`).value,checks,date:new Date().toISOString()};logActivity('Simulation Saved',sim.sec,sim.title);save();alert('Simulation saved. Self-check: '+checks.filter(Boolean).length+' of '+checks.length);}
function flash(){let fs=areaFlash();let idx=Math.max(0,Math.min(state.flashIndex[state.section]||0,fs.length-1));let f=fs[idx];let status=state.flash[f.id]||'new';$('app').innerHTML=`<div class="card"><h2>${sectionName(state.section)} — Flashcards</h2><p class="muted">Card ${idx+1} of ${fs.length}</p><div class="card"><h3>${f.front}</h3><p>${state.showBack?f.back:'Tap Flip Card to show the answer.'}</p><p><span class="pill">${status}</span></p><div class="actions"><button onclick="state.showBack=!state.showBack;save();flash()">Flip Card</button><button ${idx===0?'disabled':''} onclick="flashMove(-1)">Previous</button><button ${idx===fs.length-1?'disabled':''} onclick="flashMove(1)">Next</button><button onclick="setFlashStatus('${f.id}','learning')">Learning</button><button class="primary" onclick="setFlashStatus('${f.id}','mastered')">Mastered</button></div></div></div>`}
function flashMove(delta){let fs=areaFlash();let idx=Math.max(0,Math.min((state.flashIndex[state.section]||0)+delta,fs.length-1));state.flashIndex[state.section]=idx;state.showBack=false;logActivity('Flashcard Reviewed',state.section,fs[idx].front);save();flash();}
function setFlashStatus(id,status){state.flash[id]=status;logActivity('Flashcard '+status,state.section,id);save();flash();}
function read(){let rows=READINGS[state.section]||[];logActivity('Reading Opened',state.section,sectionName(state.section));$('app').innerHTML=`<div class="card"><h2>${sectionName(state.section)} — Readings</h2><p class="muted">Expanded outline-level review notes. Use with MCQs and simulations.</p></div>`+rows.map(r=>`<div class="card"><h3>${r.topic}</h3><h4>Key rules</h4><ul>${r.rules.map(x=>`<li>${x}</li>`).join('')}</ul><h4>Common CPA traps</h4><ul>${r.traps.map(x=>`<li>${x}</li>`).join('')}</ul><h4>Exam example</h4><p>${r.example}</p></div>`).join('')}
function missed(){let list=Object.values(state.missed).sort((a,b)=>new Date(b.lastMissed)-new Date(a.lastMissed));$('app').innerHTML=`<div class="card"><h2>Missed Questions Log</h2><div class="actions"><button onclick="retakeMissed(10,false)">Retake 10 Missed</button><button onclick="retakeMissed(999,false)">Retake All Missed</button><button class="primary" onclick="retakeMissed(10,true)">Take 10 Related Questions</button></div></div>`+(list.length?list.map(m=>`<div class="card"><b>${sectionName(m.sec)}</b> · ${m.topic} · missed ${m.count} time(s)<p>${m.q}</p><p class="muted">Last answer: ${m.lastAnswer} · Correct: ${m.ans}</p><p>${m.exp}</p></div>`).join(''):'<div class="card">No missed questions yet.</div>')}
function retakeMissed(n,related){let miss=Object.values(state.missed);let ids=miss.map(m=>m.id);if(related){let secs=new Set(miss.map(m=>m.sec)), topics=new Set(miss.map(m=>m.topic));let rel=QUESTIONS.filter(q=>secs.has(q.sec)&&(topics.has(q.topic)||ids.includes(q.id)));if(rel.length<10) rel=QUESTIONS.filter(q=>secs.has(q.sec));ids=rel.map(q=>q.id);}startQuiz(n,ids);}
function dailySummary(entries){let mcq=entries.filter(e=>e.type.startsWith('MCQ'));let correct=entries.filter(e=>e.type==='MCQ Correct').length;let sims=entries.filter(e=>e.type==='Simulation Saved').length;let reads=entries.filter(e=>e.type==='Reading Opened').length;let flash=entries.filter(e=>e.type.startsWith('Flashcard')).length;return `<div class="grid"><div><b>Total Activities</b><div class="metric">${entries.length}</div></div><div><b>MCQ Accuracy</b><div class="metric">${pct(correct,mcq.length)}%</div></div><div><b>Simulations</b><div class="metric">${sims}</div></div><div><b>Readings / Flashcards</b><div class="metric">${reads}/${flash}</div></div></div>`}
function calendar(){let dates=Object.keys(state.progress).sort().reverse();$('app').innerHTML=`<div class="card"><h2>Daily Progress Log</h2><p class="muted">Daily summary plus activity detail.</p></div>`+(dates.length?dates.map(d=>{let entries=state.progress[d];return `<div class="card"><h3>${d}</h3>${dailySummary(entries)}<table><tr><th>Time</th><th>Activity</th><th>Area</th><th>Detail</th></tr>${entries.map(e=>`<tr><td>${e.time}</td><td>${e.type}</td><td>${sectionName(e.sec)}</td><td>${e.detail}</td></tr>`).join('')}</table></div>`}).join(''):'<div class="card">No activity yet.</div>')}
function exam(){if(state.examRun)return examRun();let totalQs=QUESTIONS.length,totalSims=SIMS.length;$('app').innerHTML=`<div class="card"><h2>Exam Mode</h2><p class="muted">CPA-style simulator: multiple-choice testlet first, then simulations. Answers are not shown during exam mode; scoring appears after submission.</p><div class="actions"><button class="primary" onclick="startExam(20,1)">Mini Exam: 20 MCQs + 1 TBS</button><button onclick="startExam(40,2)">Half Practice: 40 MCQs + 2 TBSs</button><button class="warn" onclick="startExam(${totalQs},${totalSims})">Full Exam Set: ${totalQs} MCQs + ${totalSims} TBSs</button></div><ol><li>MCQs are presented first.</li><li>Simulations open after the MCQ testlet is complete.</li><li>Final report shows MCQ score by area and confirms TBS completion.</li></ol></div>`}
function startExam(n,tbs){let ids=QUESTIONS.slice().sort(()=>Math.random()-.5).slice(0,Math.min(n,QUESTIONS.length)).map(q=>q.id);let sids=SIMS.slice().sort(()=>Math.random()-.5).slice(0,Math.min(tbs,SIMS.length)).map(s=>s.id);state.examRun={ids,sids,idx:0,simIdx:0,score:0,answered:false,selected:null,simResponses:{},phase:'mcq'};logActivity('Exam Mode Started','mixed',`${ids.length} MCQs + ${sids.length} TBS`);save();examRun();}
function examRun(){let ex=state.examRun;if(!ex)return exam();if(ex.phase==='tbs')return examTbs();if(ex.idx>=ex.ids.length){ex.phase='tbs';ex.simIdx=0;save();return examTbs();}let q=QUESTIONS.find(x=>x.id===ex.ids[ex.idx]);$('app').innerHTML=`<div class="card"><h2>Exam Mode — MCQ Testlet</h2><p class="muted">Question ${ex.idx+1} of ${ex.ids.length} · ${sectionName(q.sec)} · ${qMeta(q)}</p><h3>${q.q}</h3>${q.choices.map((c,i)=>{let L=String.fromCharCode(65+i);let picked=ex.selected===L?' selected':'';return `<button class="choice${picked}" onclick="examAnswer('${L}')"><b>${L}.</b> ${c}</button>`}).join('')}<p class="muted">Exam mode hides explanations until the final report.</p>${ex.answered?`<button class="primary" onclick="examNext()">${ex.idx+1===ex.ids.length?(ex.sids.length?'Continue to Simulations':'Submit Exam'):'Next'}</button>`:''}</div>`}
function examAnswer(letter){let ex=state.examRun;if(ex.answered)return;let q=QUESTIONS.find(x=>x.id===ex.ids[ex.idx]);let correct=letter===q.ans;ex.answered=true;ex.selected=letter;if(correct)ex.score++;state.answered[q.id]={correct,selected:letter,date:new Date().toISOString(),sec:q.sec,topic:q.topic};if(!correct){state.missed[q.id]=state.missed[q.id]||{id:q.id,sec:q.sec,topic:q.topic,q:q.q,ans:q.ans,exp:q.exp,count:0};state.missed[q.id].count++;state.missed[q.id].lastAnswer=letter;state.missed[q.id].lastMissed=new Date().toISOString();}save();examRun();}
function examNext(){let ex=state.examRun;ex.idx++;ex.answered=false;ex.selected=null;save();examRun();}
function examTbs(){let ex=state.examRun;if(!ex.sids.length||ex.simIdx>=ex.sids.length)return finishExam();let sim=SIMS.find(s=>s.id===ex.sids[ex.simIdx]);let saved=ex.simResponses[sim.id]||{text:'',checks:[]};$('app').innerHTML=`<div class="card"><h2>Exam Mode — Simulation ${ex.simIdx+1} of ${ex.sids.length}</h2><p class="muted">${sectionName(sim.sec)} · Complete after MCQs.</p><h3>${sim.title}</h3><p>${sim.prompt}</p><button onclick="toggleExhibits('${sim.id}')">Open Exhibits</button><div id="ex-${sim.id}" style="display:none">${sim.exhibitBodies.map((b,i)=>`<pre><b>${sim.exhibits[i]}</b>\n${b}</pre>`).join('')}</div><h4>Tasks</h4><ol>${sim.tasks.map(t=>`<li>${t}</li>`).join('')}</ol><textarea id="exam-sim-${sim.id}" placeholder="Enter your simulation response here.">${saved.text||''}</textarea><h4>Self-check items</h4>${sim.rubric.map((r,i)=>`<label><input type="checkbox" id="exam-${sim.id}-${i}" ${saved.checks?.[i]?'checked':''}> ${r}</label><br>`).join('')}<div class="actions"><button onclick="saveExamSim('${sim.id}',false)">Save TBS Response</button><button class="primary" onclick="saveExamSim('${sim.id}',true)">${ex.simIdx+1===ex.sids.length?'Submit Exam':'Next Simulation'}</button></div></div>`}
function saveExamSim(id,advance){let ex=state.examRun;let sim=SIMS.find(s=>s.id===id);let checks=sim.rubric.map((_,i)=>$(`exam-${id}-${i}`).checked);ex.simResponses[id]={text:$(`exam-sim-${id}`).value,checks,date:new Date().toISOString(),sec:sim.sec,title:sim.title};state.sim[id]=ex.simResponses[id];logActivity('Exam TBS Saved',sim.sec,sim.title);if(advance)ex.simIdx++;save();examTbs();}
function finishExam(){let ex=state.examRun,total=ex.ids.length,p=pct(ex.score,total);let by={};ex.ids.forEach(id=>{let q=QUESTIONS.find(x=>x.id===id);by[q.sec]=by[q.sec]||{n:0,c:0};by[q.sec].n++;if(state.answered[id]?.correct)by[q.sec].c++;});let tbsDone=Object.keys(ex.simResponses||{}).length;let tbsList=ex.sids.map(id=>SIMS.find(s=>s.id===id)).filter(Boolean);state.examRun=null;logActivity('Exam Mode Submitted','mixed',`${p}% + ${tbsDone} TBS`);save();$('app').innerHTML=`<div class="card"><h2>Exam Submitted</h2><p class="metric">${p}%</p><p>${ex.score} correct of ${total} MCQs. Simulations completed: ${tbsDone} of ${ex.sids.length}.</p><h3>Performance by Area</h3><ul>${Object.entries(by).map(([k,v])=>`<li>${sectionName(k)}: ${pct(v.c,v.n)}%</li>`).join('')}</ul><h3>TBS Set</h3><ul>${tbsList.map(s=>`<li>${sectionName(s.sec)} — ${s.title}</li>`).join('')}</ul><button class="primary" onclick="state.view='Exam Mode';save();render()">Back to Exam Mode</button></div>`}
function systemHealth(){let checks=[['Unique question IDs',new Set(QUESTIONS.map(q=>q.id)).size===QUESTIONS.length],['At least 20 MCQs per area',SECTIONS.every(s=>areaQs(s.id).length>=20)],['Every question has four choices',QUESTIONS.every(q=>q.choices.length===4)],['Every answer key is A-D',QUESTIONS.every(q=>'ABCD'.includes(q.ans))],['Every question has metadata',QUESTIONS.every(q=>q.difficulty&&q.questionType&&q.sourceType&&q.topic&&q.sec)],['All flashcard decks have specific examples',FLASHCARDS.every(f=>f.back.includes('Example:')&&f.back.includes('CPA trap:'))],['All areas have simulations',SECTIONS.every(s=>areaSims(s.id).length>=2)],['Full Exam Set available',QUESTIONS.length>=80&&SIMS.length>=8],['Progress backup available','Export + Import implemented']];$('app').innerHTML=`<div class="card"><h2>System Health</h2><p class="muted">Student-facing status replacing internal QA checks.</p><table><tr><th>Check</th><th>Status</th></tr>${checks.map(c=>`<tr><td>${c[0]}</td><td>${c[1]===true?'PASS':c[1]===false?'REVIEW':c[1]}</td></tr>`).join('')}</table></div>`}
function backup(){$('app').innerHTML=`<div class="card"><h2>Backup & Restore</h2><p class="muted">Use this before installing a new release.</p><div class="actions"><button class="primary" onclick="exportProgress()">Export Progress</button><label><input type="file" accept="application/json" onchange="importProgress(event)"> Import Progress</label><button class="danger" onclick="resetProgress()">Reset Progress</button></div></div>`}
function toggleDark(){state.dark=!state.dark;localStorage.dark=state.dark?'1':'0';save();render()}
function exportProgress(){let blob=new Blob([JSON.stringify(state,null,2)],{type:'application/json'});let a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='aud-v8-1-1-progress.json';a.click()}
function importProgress(evt){let file=evt.target.files[0];if(!file)return;let r=new FileReader();r.onload=()=>{try{let data=JSON.parse(r.result);if(!confirm('Import progress and replace current local progress?'))return;state={...freshState(),...data,version:APP_VERSION};save();render();alert('Progress imported.')}catch(e){alert('Import failed: invalid progress file.')}};r.readAsText(file);}
function resetProgress(){if(confirm('Reset all local progress? Export first if you need a backup.')){state=freshState();save();render();}}
if('serviceWorker' in navigator){navigator.serviceWorker.register('./sw.js').catch(()=>{})}
render();
